package com.hospital.management.dao.impl;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import org.junit.jupiter.api.Test;import org.mockito.MockedStatic;import java.sql.*;import java.time.LocalDate;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class PatientDaoImplTest{@Test void mapsUnlinkedPatient()throws Exception{Connection c=mock(Connection.class);PreparedStatement s=mock(PreparedStatement.class);ResultSet r=mock(ResultSet.class);when(c.prepareStatement(anyString())).thenReturn(s);when(s.executeQuery()).thenReturn(r);when(r.next()).thenReturn(true);when(r.getLong("PATIENT_ID")).thenReturn(1L);when(r.getLong("USER_ID")).thenReturn(0L);when(r.wasNull()).thenReturn(true);when(r.getString("FIRST_NAME")).thenReturn("Demo");when(r.getString("LAST_NAME")).thenReturn("Patient");when(r.getDate("DATE_OF_BIRTH")).thenReturn(Date.valueOf("1990-01-01"));try(MockedStatic<DatabaseConnectionManager> m=mockStatic(DatabaseConnectionManager.class)){m.when(DatabaseConnectionManager::getConnection).thenReturn(c);Patient p=new PatientDaoImpl().findById(1L).orElseThrow();assertNull(p.getUserId());assertEquals(LocalDate.of(1990,1,1),p.getDateOfBirth());}}@Test void createUsesGeneratedKeyWithoutCommit()throws Exception{Connection c=mock(Connection.class);PreparedStatement s=mock(PreparedStatement.class);ResultSet k=mock(ResultSet.class);when(c.prepareStatement(anyString(),any(String[].class))).thenReturn(s);when(s.getGeneratedKeys()).thenReturn(k);when(k.next()).thenReturn(true);when(k.getLong(1)).thenReturn(9L);assertEquals(9L,new PatientDaoImpl().createPatientRecord(c,patient()));verify(c,never()).commit();}@Test void linkUsesSuppliedConnection()throws Exception{Connection c=mock(Connection.class);PreparedStatement s=mock(PreparedStatement.class);when(c.prepareStatement(anyString())).thenReturn(s);when(s.executeUpdate()).thenReturn(1);assertTrue(new PatientDaoImpl().linkUserAccount(c,1L,2L));verify(c,never()).close();}@Test void blockerQueriesAreExistenceChecks()throws Exception{Connection c=mock(Connection.class);PreparedStatement s=mock(PreparedStatement.class);ResultSet r=mock(ResultSet.class);when(c.prepareStatement(anyString())).thenReturn(s);when(s.executeQuery()).thenReturn(r);when(r.next()).thenReturn(true);try(MockedStatic<DatabaseConnectionManager> m=mockStatic(DatabaseConnectionManager.class)){m.when(DatabaseConnectionManager::getConnection).thenReturn(c);assertTrue(new PatientDaoImpl().hasFutureAppointments(1L));assertTrue(new PatientDaoImpl().hasActiveAdmission(1L));}}private Patient patient(){Patient p=new Patient();p.setPatientNumber("PAT-1");p.setFirstName("Demo");p.setLastName("Patient");p.setDateOfBirth(LocalDate.of(1990,1,1));p.setGender("OTHER");p.setBloodGroup("O+");p.setPhone("9000000002");p.setStatus("ACTIVE");return p;}}
